# Analyzer module with abstract base class and concrete implementations
# Tests: abstract classes, inheritance, polymorphism, iteration, list operations

@abstract
class Analyzer:
    @abstract
    def analyze(self, data: list[int]) -> float: ...

class SumAnalyzer(Analyzer):
    @override
    def analyze(self, data: list[int]) -> float:
        total: int = 0
        for x in data:
            total += x
        return float(total)

class AverageAnalyzer(Analyzer):
    @override
    def analyze(self, data: list[int]) -> float:
        if len(data) == 0:
            return 0.0
        total: int = 0
        for x in data:
            total += x
        return float(total) / float(len(data))

class MinMaxAnalyzer(Analyzer):
    @override
    def analyze(self, data: list[int]) -> float:
        if len(data) == 0:
            return 0.0
        min_val: int = data[0]
        max_val: int = data[0]
        for x in data:
            if x < min_val:
                min_val = x
            if x > max_val:
                max_val = x
        return float(max_val - min_val)

def run_analysis(analyzer: Analyzer, data: list[int]) -> str:
    result: float = analyzer.analyze(data)
    return f"Result: {result}"
